mapper.select:
select *
from (

) feedback


        and feedbackType = #{type}


        and (
            mentorName like concat('%', #{keyword}, '%')
            or studentName like concat('%', #{keyword}, '%')
            or courseLabel like concat('%', #{keyword}, '%')
            or coalesce(assessmentTopic, '') like concat('%', #{keyword}, '%')
        )


order by updatedAt desc, feedbackId desc
